function setEntity(b){
    const e = b.closest ? (b.closest('.toggle-btn') || b) : b;
    currentEntity = e.dataset.entity;
    e.parentElement.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active'));
    e.classList.add('active');
    answers = {};
    renderQuestions();
    document.getElementById('resultSection').classList.remove('visible');
}

function renderQuestions(){
    const c = document.getElementById('questions');
    c.innerHTML = '';
    const qs = QUESTIONS[currentEntity];
    qs.forEach((q, idx) => {
        const card = document.createElement('div');
        card.className = 'question-card' + (answers[q.id] ? ' answered' : '');
        let optsHtml = q.options.map((o, oi) => {
            const selected = answers[q.id] === o.val;
            const detailHtml = o.detail ? '<small>'+o.detail+'</small>' : '';
            return '<div class="q-option '+(o.tag === 'disqualify' ? 'disqualify' : (o.tag === 'warning' ? 'warning' : ''))+(selected ? ' selected' : '')+'" onclick="setAnswer(\''+q.id+'\', \''+o.val+'\', this)"><input type="radio" name="'+q.id+'" id="'+q.id+'_'+oi+'"'+(selected ? ' checked' : '')+'><label for="'+q.id+'_'+oi+'">'+o.label+detailHtml+'</label></div>';
        }).join('');
        card.innerHTML = '<div class="q-text"><span class="q-num">'+(idx+1)+'</span><span class="q-text-body">'+q.text+'</span></div><div class="q-ref">'+q.ref+'</div><div class="q-options">'+optsHtml+'</div>';
        c.appendChild(card);
    });
}

function setAnswer(qid, val, optElem){
    answers[qid] = val;
    const card = optElem.closest('.question-card');
    card.classList.add('answered');
    // update radio + selected class
    card.querySelectorAll('.q-option').forEach(o => o.classList.remove('selected'));
    optElem.classList.add('selected');
    card.querySelectorAll('input[type=radio]').forEach(r => r.checked = false);
    optElem.querySelector('input[type=radio]').checked = true;
}

function evaluate(){
    const qs = QUESTIONS[currentEntity];
    const unanswered = qs.filter(q => !answers[q.id]);
    if(unanswered.length > 0){
        showError('Please answer all '+qs.length+' questions. Missing: Q'+qs.findIndex(q => !answers[q.id])+1);
        return;
    }

    const blockers = [];
    const actions = [];
    let passCount = 0;

    qs.forEach(q => {
        const ans = answers[q.id];
        const opt = q.options.find(o => o.val === ans);
        if(!opt) return;
        if(opt.tag === 'disqualify'){
            blockers.push({
                title: q.text,
                statute: q.ref.split('—')[0].trim(),
                detail: opt.detail || opt.label,
                action: 'Resolve this blocker before filing.'
            });
        } else if(opt.tag === 'warning'){
            actions.push({
                title: q.text,
                statute: q.ref.split('—')[0].trim(),
                detail: opt.detail || opt.label,
                action: 'Complete this cleanup step before filing.'
            });
        } else {
            passCount++;
        }
    });

    // Determine verdict
    let verdict, vIcon, vLabel, vTitle, vSub, vClass;
    if(blockers.length > 0){
        verdict = 'not-eligible';
        vIcon = '⛔';
        vLabel = 'Verdict';
        vTitle = 'NOT YET ELIGIBLE';
        vSub = blockers.length + ' hard blocker(s) under Section 248/249 or pending statutory dues. Address these before filing STK-2 / Form 24. ROC will reject the application and keep the fee.';
    } else if(actions.length > 0){
        verdict = 'conditional';
        vIcon = '⚠';
        vLabel = 'Verdict';
        vTitle = 'CONDITIONAL — Eligible After Cleanup';
        vSub = actions.length + ' cleanup step(s) to complete before filing. No hard statutory blockers. Estimated cleanup time: 30-90 days depending on bank closure, charge satisfaction, and creditor settlement.';
    } else {
        verdict = 'eligible';
        vIcon = '✓';
        vLabel = 'Verdict';
        vTitle = 'ELIGIBLE — Ready to File';
        vSub = 'All 10 statutory criteria met. You can proceed with '+(currentEntity === 'llp' ? 'Form 24 (LLP Rule 37)' : 'Form STK-2 (Section 248)')+'. Patron can complete drafting, notarisation, e-filing and ROC follow-up in 4-9 months.';
    }

    document.getElementById('verdictBanner').innerHTML =
        '<div class="verdict-banner '+verdict+'">'+
            '<span class="v-icon">'+vIcon+'</span>'+
            '<div class="v-label">'+vLabel+'</div>'+
            '<div class="v-title">'+vTitle+'</div>'+
            '<div class="v-sub">'+vSub+'</div>'+
        '</div>';

    document.getElementById('resBlockers').textContent = blockers.length;
    document.getElementById('resActions').textContent = actions.length;
    document.getElementById('resPass').textContent = passCount;

    let panel = '';
    if(blockers.length > 0){
        panel += '<div class="section-head">Hard Blockers — Cannot File Until Resolved <span style="font-size:11px;color:var(--danger);background:#FEE2E2;padding:2px 8px;border-radius:10px;">'+blockers.length+'</span></div>';
        blockers.forEach(b => {
            panel += '<div class="issue-card blocker"><div class="issue-head"><span class="issue-statute">'+b.statute+'</span>'+b.title+'</div><div class="issue-body">'+b.detail+'<div class="action-required"><strong>Required:</strong> '+b.action+'</div></div></div>';
        });
    }
    if(actions.length > 0){
        panel += '<div class="section-head">Cleanup Steps Before Filing <span style="font-size:11px;color:var(--accent);background:#FED7AA;padding:2px 8px;border-radius:10px;">'+actions.length+'</span></div>';
        actions.forEach(a => {
            panel += '<div class="issue-card action"><div class="issue-head"><span class="issue-statute">'+a.statute+'</span>'+a.title+'</div><div class="issue-body">'+a.detail+'<div class="action-required"><strong>Action:</strong> '+a.action+'</div></div></div>';
        });
    }
    if(blockers.length === 0 && actions.length === 0){
        panel += '<div class="section-head">Next Steps</div>';
        if(currentEntity === 'llp'){
            panel += '<div class="issue-card action" style="border-left-color:var(--success);background:#F0FDF4;"><div class="issue-head"><span class="issue-statute" style="background:#D1FAE5;color:#065F46;">LLP Rule 37</span>File Form 24 with MCA</div><div class="issue-body">All criteria met. Engage a CA/CS to draft affidavits, indemnity bonds, statement of accounts, and partner consent. File Form 24 (govt fee ₹500) + supporting documents. Public notice period 30 days + processing 90-120 days. <div class="action-required"><strong>Patron service:</strong> End-to-end LLP strike off (Form 24) — fixed-fee ₹10,000-₹18,000, 3-6 months. <a href="/llp-strike-off-form-24" style="color:var(--primary)">Learn more →</a></div></div></div>';
        } else {
            panel += '<div class="issue-card action" style="border-left-color:var(--success);background:#F0FDF4;"><div class="issue-head"><span class="issue-statute" style="background:#D1FAE5;color:#065F46;">Sec 248(2)</span>File Form STK-2 with ROC</div><div class="issue-body">All criteria met. Engage a CA/CS to draft Form STK-3 (indemnity bonds), STK-4 (affidavits), STK-8 (litigation statement), special resolution, statement of accounts. File STK-2 (govt fee ₹10,000) + supporting documents. Public notice period 30 days + processing 60-120 days. <div class="action-required"><strong>Patron service:</strong> End-to-end strike off (STK-2) — fixed-fee ₹15,000-₹35,000, 4-9 months. <a href="/strike-off-private-limited-company" style="color:var(--primary)">Learn more →</a></div></div></div>';
        }
    }

    document.getElementById('issuesPanel').innerHTML = panel;

    // Post-CTA dynamic head
    let head;
    if(verdict === 'eligible') head = 'You\u2019re eligible — let Patron file STK-2 / Form 24 with 98% first-time approval';
    else if(verdict === 'conditional') head = 'Engage Patron to handle the cleanup + filing in a single workflow';
    else head = 'Address the blockers with Patron\u2019s cleanup service before applying';
    document.getElementById('postCtaHead').textContent = head;

    const sec = document.getElementById('resultSection');
    sec.classList.add('visible');
    requestAnimationFrame(function(){requestAnimationFrame(function(){sec.scrollIntoView({behavior:'smooth',block:'start'});});});
}

function resetCalc(){
    currentEntity = 'pvtltd';
    answers = {};
    document.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active'));
    document.querySelector('.toggle-btn[data-entity="pvtltd"]').classList.add('active');
    renderQuestions();
    document.getElementById('resultSection').classList.remove('visible');
    document.getElementById('errorBanner').classList.remove('visible');
}

function toggleFaq(e){const b=e.closest?(e.closest('.faq-question')||e):e;const it=b.closest('.faq-item');if(!it)return;const o=it.classList.contains('open');document.querySelectorAll('.faq-item').forEach(i=>{i.classList.remove('open');const q=i.querySelector('.faq-question');if(q)q.setAttribute('aria-expanded','false');});if(!o){it.classList.add('open');b.setAttribute('aria-expanded','true');}}

const navLinks=document.querySelectorAll('.toc-nav a');
window.addEventListener('scroll',()=>{const s=document.querySelectorAll('section[id], header[id]');let c='';s.forEach(x=>{const t=x.offsetTop-100;if(window.pageYOffset>=t)c=x.getAttribute('id');});navLinks.forEach(l=>{l.classList.toggle('active',l.getAttribute('href')==='#'+c);});});

// Initial render
renderQuestions();
</script>


